public abstract class BaseEntity {
    protected long id;
    public BaseEntity(long id) { this.id = id; }
    public abstract void process();
    public void printId() { System.out.println("ID: " + id); }
}

public class ConcreteEntity extends BaseEntity {
    public ConcreteEntity(long id) { super(id); }
    @Override
    public void process() { System.out.println("Processing entity " + id); }
}

public class Main {
    public static void main(String[] args) {
        BaseEntity entity = new ConcreteEntity(1L);
        entity.process();
        entity.printId();
    }
}
